use chroma_types::Metadata;
let mut metadata = Metadata::new();
metadata.insert("key".to_string(), "value".into());
collection.modify(Some("new_name"), Some(metadata)).await?;

use chroma_types::{Where, MetadataExpression, MetadataComparison, MetadataValue, PrimitiveOperator};
let where_clause = Where::Metadata(MetadataExpression {
    key: "category".to_string(),
    comparison: MetadataComparison::Primitive(PrimitiveOperator::Equal, MetadataValue::Str("old".to_string())),
});
collection.delete(None, Some(where_clause)).await?;

use chroma_types::IncludeList;
let response = collection.get(
    Some(vec!["id1".to_string(), "id2".to_string()]),
    None,
    None,
    None,
    Some(IncludeList::default_get())
).await?;

use chroma_types::{Where, MetadataExpression, MetadataComparison, MetadataValue, PrimitiveOperator, IncludeList};
let where_clause = Where::Metadata(MetadataExpression {
    key: "category".to_string(),
    comparison: MetadataComparison::Primitive(PrimitiveOperator::Equal, MetadataValue::Str("science".to_string())),
});
let response = collection.get(None, Some(where_clause), Some(10), None, None).await?;

let results = collection.query(
    vec![vec![0.1, 0.2, 0.3]],
    Some(10),
    None,
    None,
    None
).await?;

use chroma_types::{Where, MetadataExpression, MetadataComparison, MetadataValue, PrimitiveOperator};
let where_clause = Where::Metadata(MetadataExpression {
    key: "category".to_string(),
    comparison: MetadataComparison::Primitive(PrimitiveOperator::Equal, MetadataValue::Str("science".to_string())),
});
let results = collection.query(
    vec![vec![0.1, 0.2, 0.3]],
