    Some(where_clause),
    None,
    None
).await?;

use chroma_types::plan::{SearchPayload, ReadLevel};
use chroma_types::operator::{RankExpr, QueryVector, Key};
let search = SearchPayload::default()
    .rank(RankExpr::Knn {
        query: QueryVector::Dense(vec![0.1, 0.2, 0.3]),
        key: Key::Embedding,
        limit: 10,
        default: None,
        return_rank: false,
    })
    .limit(Some(10), 0)
    .select([Key::Document, Key::Score]);
let results = collection.search(vec![search]).await?;

use chroma_types::plan::{SearchPayload, ReadLevel};
use chroma_types::operator::{RankExpr, QueryVector, Key};
let search = SearchPayload::default()
    .r#where(Key::field("category").eq("science"))
    .rank(RankExpr::Knn {
        query: QueryVector::Dense(vec![0.1, 0.2, 0.3]),
        key: Key::Embedding,
        limit: 100,
        default: None,
        return_rank: false,
    })
    .limit(Some(10), 0)
    .select([Key::Document, Key::Score]);
let results = collection.search(vec![search]).await?;

use chroma_types::UpdateMetadata;
let mut metadata = UpdateMetadata::new();
metadata.insert("key".to_string(), chroma_types::UpdateMetadataValue::Str("value".to_string()));
collection.update(
    vec!["id1".to_string()],
    None,
    Some(vec![Some("updated doc".to_string())]),
    None,
    Some(vec![Some(metadata)])
).await?;
